export function runScenario(scenarioJson: string): CliResult {
  const scenario: Scenario = JSON.parse(scenarioJson);
  for (const step of scenario.steps) {
    if (step.op === "claim") continue;
    for (const item of step.items) {
      if (!KNOWN_ITEM_TYPES.has(item.type)) {
        return { stdout: "", stderr: `unknown item type: ${item.type}`, exitCode: 1 };
      }
    }
  }
  const results = scenario.steps.map((step) => {
    if (step.op === "claim") {
      const policyStep = scenario.steps[step.policy] as QuoteStep;
      return claim({ items: policyStep.items }, step.incident);
    }
    return { premium: quote(scenario.customer, step.items) };
  });
  return { stdout: JSON.stringify({ results }), stderr: "", exitCode: 0 };
}
```

Same conditional count (3), same loop count (3), same invocations — mass is essentially **~54** (unchanged from original). The guard clause `if (...) continue;` and `if (...) { for ... }` are both one conditional + one loop. So mass is identical, but the guard clause flattens nesting by one level — pure Rule 2 win at zero mass cost.

